Use MSTest's `[DataTestMethod]` with `[DataRow]` to make these data-driven. Each new case becomes a single attribute line:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Validation.Tests;

[TestClass]
public sealed class InputValidatorTests
{
    private InputValidator _validator = null!;

    [TestInitialize]
    public void Setup() => _validator = new InputValidator();

    [DataTestMethod]
    [DataRow("", false, "Input cannot be empty", DisplayName = "Empty string")]
    [DataRow(null, false, "Input cannot be empty", DisplayName = "Null")]
    [DataRow("   ", false, "Input cannot be empty", DisplayName = "Whitespace only")]
    [DataRow("ab", false, "Input must be at least 3 characters", DisplayName = "Too short")]
    [DataRow("hello<script>", false, "Input contains invalid characters", DisplayName = "Special chars")]
    [DataRow("abc", true, null, DisplayName = "Min length")]
    [DataRow("hello-world", true, null, DisplayName = "Valid input")]
    public void Validate_ReturnsExpectedResult(string? input, bool expectedValid, string? expectedError)
    {
        var result = _validator.Validate(input);

        Assert.AreEqual(expectedValid, result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    [TestMethod]
    public void Validate_TooLong_ReturnsFalse()
    {
        // DataRow requires compile-time constants, so computed inputs stay as separate tests
        var result = _validator.Validate(new string('x', 256));

        Assert.IsFalse(result.IsValid);
        Assert.AreEqual("Input must not exceed 255 characters", result.ErrorMessage);
    }

    [TestMethod]
    public void Validate_MaxLength_ReturnsTrue()
    {
        var result = _validator.Validate(new string('a', 255));

        Assert.IsTrue(result.IsValid);
        Assert.IsNull(result.ErrorMessage);
    }
}
```

**Key changes:**

- **`[DataRow]`** — each case is one line; adding a new case = adding one attribute
- **`[TestInitialize]`** — eliminates repeated `new InputValidator()` in every method
- **`DisplayName`** — gives readable names in test output
- Cases needing computed values (`new string(...)`) stay as separate methods since `DataRow` requires compile-time constants

If you outgrow `DataRow`, look at `[DynamicData]` which can pull test cases from a property or method — that handles computed values too.
